import{_ as a,c as i,o as r,aq as t}from"./chunks/framework.jeRwkH3J.js";const g=JSON.parse('{"title":"Plugin package format","description":"How Usagi discovers and installs external source plugins.","frontmatter":{"title":"Plugin package format","description":"How Usagi discovers and installs external source plugins.","footer":false},"headers":[],"relativePath":"dev/parsers-library/index.md","filePath":"dev/parsers-library/index.md","lastUpdated":1776454353000,"breadcrumbs":[{"text":"For developers","items":[{"text":"Contribute","link":"/dev/contribute/"},{"text":"Plugin package format","link":"/dev/parsers-library/"},{"text":"Synchronization server","link":"/dev/sync-server/"},{"text":"External plugins SDK","link":"/dev/plugin-sdk/"}]},{"text":"Plugin package format","link":"/dev/parsers-library/"}]}'),o={name:"dev/parsers-library/index.md"};function n(l,e,s,d,u,p){return r(),i("div",null,[...e[0]||(e[0]=[t('<h1 id="plugin-package-format" tabindex="-1">Plugin package format <a class="header-anchor" href="#plugin-package-format" aria-label="Permalink to &quot;Plugin package format&quot;">​</a></h1><p>Usagi does not bundle online source packs inside the app. Online sources are provided by external plugins distributed as <code>.jar</code> files.</p><h2 id="how-plugin-loading-works" tabindex="-1">How plugin loading works <a class="header-anchor" href="#how-plugin-loading-works" aria-label="Permalink to &quot;How plugin loading works&quot;">​</a></h2><p>When a plugin is imported, Usagi stores the <code>.jar</code> and reloads available sources from that file. Loaded sources then appear in <strong>Sources Catalog</strong>.</p><h2 id="distribution-requirements" tabindex="-1">Distribution requirements <a class="header-anchor" href="#distribution-requirements" aria-label="Permalink to &quot;Distribution requirements&quot;">​</a></h2><ul><li>Plugin artifact must be a <code>.jar</code> file.</li><li>For <strong>Import from GitHub</strong>, the latest release must contain at least one <code>.jar</code> asset.</li><li>Use stable source identifiers between versions to avoid breaking user data mappings.</li><li>Keep plugin and app versions compatible. Incompatible plugins will fail to load.</li></ul><h2 id="installation-flow-for-users" tabindex="-1">Installation flow for users <a class="header-anchor" href="#installation-flow-for-users" aria-label="Permalink to &quot;Installation flow for users&quot;">​</a></h2><ol><li>Open <strong>Settings</strong> -&gt; <strong>Sources</strong> -&gt; <strong>Manage plugins</strong>.</li><li>Tap <strong>+</strong>.</li><li>Choose one import mode: <ul><li><strong>Import from GitHub</strong> (enter <code>owner/repository</code>).</li><li><strong>Import from local storage</strong> (pick a <code>.jar</code>).</li></ul></li><li>After successful import, open <strong>Sources Catalog</strong> and enable the sources you need.</li></ol><h2 id="updating-and-removing-plugins" tabindex="-1">Updating and removing plugins <a class="header-anchor" href="#updating-and-removing-plugins" aria-label="Permalink to &quot;Updating and removing plugins&quot;">​</a></h2><ul><li>Update by importing a newer plugin release (same filename can be overwritten).</li><li>Remove plugins from <strong>Manage plugins</strong>.</li><li>If plugin loading fails, confirm that the file is a valid <code>.jar</code> and built for the current app version.</li></ul><h2 id="for-plugin-authors" tabindex="-1">For plugin authors <a class="header-anchor" href="#for-plugin-authors" aria-label="Permalink to &quot;For plugin authors&quot;">​</a></h2><ul><li>Start with <a href="/dev/plugin-sdk/">External plugins SDK</a>.</li><li>Validate plugin import and source behavior on a real Usagi build before publishing.</li></ul><h2 id="contribution" tabindex="-1">Contribution <a class="header-anchor" href="#contribution" aria-label="Permalink to &quot;Contribution&quot;">​</a></h2><p>Check <a href="/dev/contribute/">Contribute</a> for project-wide contribution guidelines.</p><h2 id="dmca-disclaimer" tabindex="-1">DMCA disclaimer <a class="header-anchor" href="#dmca-disclaimer" aria-label="Permalink to &quot;DMCA disclaimer&quot;">​</a></h2><p>The developer(s) of this application does not have any affiliation with the content providers available. If there is any content, it&#39;s provided by external libraries (added / imported by users); the application itself doesn&#39;t include any built-in content.</p>',16)])])}const h=a(o,[["render",n]]);export{g as __pageData,h as default};
